import{_ as t,c as s,o as a,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"上下文注入: Agent 未卜先知 | opencode-supermemory","description":"学习 opencode-supermemory 的自动上下文注入机制。了解 Agent 如何在会话开始时获取用户画像和项目知识，掌握关键词触发记忆保存的方法。","frontmatter":{"title":"上下文注入: Agent 未卜先知 | opencode-supermemory","sidebarTitle":"让 Agent 未卜先知","subtitle":"上下文注入: Agent 未卜先知","description":"学习 opencode-supermemory 的自动上下文注入机制。了解 Agent 如何在会话开始时获取用户画像和项目知识，掌握关键词触发记忆保存的方法。","tags":["context","injection","prompt","memory"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"zh/supermemoryai/opencode-supermemory/core/context-injection/index.md","filePath":"zh/supermemoryai/opencode-supermemory/core/context-injection/index.md"}'),o={name:"zh/supermemoryai/opencode-supermemory/core/context-injection/index.md"};function i(r,e,l,p,d,c){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="自动上下文注入机制-让-agent-未卜先知" tabindex="-1">自动上下文注入机制：让 Agent &quot;未卜先知&quot; <a class="header-anchor" href="#自动上下文注入机制-让-agent-未卜先知" aria-label="Permalink to &quot;自动上下文注入机制：让 Agent &quot;未卜先知&quot;&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><p>学完本课，你将能够：</p><ol><li><strong>理解</strong> 为什么 Agent 一上来就知道你的编码习惯和项目架构。</li><li><strong>掌握</strong> 上下文注入的 &quot;三维模型&quot;（用户画像、项目知识、相关记忆）。</li><li><strong>学会</strong> 使用关键词（如 &quot;Remember this&quot;）主动干预 Agent 的记忆行为。</li><li><strong>配置</strong> 注入的条目数量，平衡上下文长度与信息丰富度。</li></ol><hr><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>在没有记忆插件之前，每次开启新会话，Agent 都是一张白纸。你必须重复告诉它：&quot;我是用 TypeScript 的&quot;、&quot;这个项目用的是 Next.js&quot;。</p><p><strong>上下文注入（Context Injection）</strong> 解决了这个问题。它就像在 Agent 醒来的一瞬间，把一份 &quot;任务简报&quot; 塞进它的脑子里。</p><h3 id="触发时机" tabindex="-1">触发时机 <a class="header-anchor" href="#触发时机" aria-label="Permalink to &quot;触发时机&quot;">​</a></h3><p>opencode-supermemory 极其克制，只在 <strong>会话的第一条消息</strong> 时触发自动注入。</p><ul><li><strong>为什么是第一条？</strong> 因为这是确立会话基调的关键时刻。</li><li><strong>后续消息呢？</strong> 后续消息不再自动注入，以免干扰对话流，除非你主动触发（见下文 &quot;关键词触发&quot;）。</li></ul><h3 id="三维注入模型" tabindex="-1">三维注入模型 <a class="header-anchor" href="#三维注入模型" aria-label="Permalink to &quot;三维注入模型&quot;">​</a></h3><p>插件会并行获取三类数据，组合成一个 <code>[SUPERMEMORY]</code> 提示块：</p><table tabindex="0"><thead><tr><th>数据维度</th><th>来源</th><th>作用</th><th>示例</th></tr></thead><tbody><tr><td><strong>1. 用户画像</strong> (Profile)</td><td><code>getProfile</code></td><td>你的长期偏好</td><td>&quot;用户喜欢函数式编程&quot;、&quot;偏好箭头函数&quot;</td></tr><tr><td><strong>2. 项目知识</strong> (Project)</td><td><code>listMemories</code></td><td>当前项目的全局知识</td><td>&quot;本项目使用 Clean Architecture&quot;、&quot;API 放在 src/api&quot;</td></tr><tr><td><strong>3. 相关记忆</strong> (Relevant)</td><td><code>searchMemories</code></td><td>与你第一句话相关的过往经验</td><td>你问 &quot;怎么修这个 Bug&quot;，它搜出之前的类似修复记录</td></tr></tbody></table><hr><h2 id="注入了什么" tabindex="-1">注入了什么？ <a class="header-anchor" href="#注入了什么" aria-label="Permalink to &quot;注入了什么？&quot;">​</a></h2><p>当你在 OpenCode 中发送第一条消息时，插件会在后台默默地将以下内容插入到 System Prompt 中。</p><details class="details custom-block"><summary>点击查看注入内容的真实结构</summary><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[SUPERMEMORY]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User Profile:</span></span>
<span class="line"><span>- User prefers concise responses</span></span>
<span class="line"><span>- User uses Zod for all validations</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Recent Context:</span></span>
<span class="line"><span>- Working on auth module refactoring</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Project Knowledge:</span></span>
<span class="line"><span>- [100%] Architecture follows MVC pattern</span></span>
<span class="line"><span>- [100%] Use &#39;npm run test&#39; for testing</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Relevant Memories:</span></span>
<span class="line"><span>- [85%] Previous fix for hydration error: use useEffect</span></span></code></pre></div></details><p>Agent 看到这些信息后，就会表现得像一个在这个项目工作了很久的老员工，而不是新来的实习生。</p><hr><h2 id="关键词触发机制-nudge" tabindex="-1">关键词触发机制 (Nudge) <a class="header-anchor" href="#关键词触发机制-nudge" aria-label="Permalink to &quot;关键词触发机制 (Nudge)&quot;">​</a></h2><p>除了开头的自动注入，你还可以在对话过程中随时 &quot;唤醒&quot; 记忆功能。</p><p>插件内置了一个 <strong>关键词检测器</strong>。只要你的消息中包含特定的触发词，插件就会向 Agent 发送一个 &quot;隐形提示&quot;（Nudge），强制它调用保存工具。</p><h3 id="默认触发词" tabindex="-1">默认触发词 <a class="header-anchor" href="#默认触发词" aria-label="Permalink to &quot;默认触发词&quot;">​</a></h3><ul><li><code>remember</code></li><li><code>save this</code></li><li><code>don&#39;t forget</code></li><li><code>memorize</code></li><li><code>take note</code></li><li>... (更多见源码配置)</li></ul><h3 id="交互示例" tabindex="-1">交互示例 <a class="header-anchor" href="#交互示例" aria-label="Permalink to &quot;交互示例&quot;">​</a></h3><p><strong>你输入</strong>：</p><blockquote><p>这里的 API 响应格式变了，<strong>remember</strong> 以后都用 <code>data.result</code> 而不是 <code>data.payload</code>。</p></blockquote><p><strong>插件检测到 &quot;remember&quot;</strong>：</p><blockquote><p>（后台注入提示）：<code>[MEMORY TRIGGER DETECTED] The user wants you to remember something...</code></p></blockquote><p><strong>Agent 反应</strong>：</p><blockquote><p>收到。我会记住这个变更。 <em>(后台调用 <code>supermemory.add</code> 保存记忆)</em></p></blockquote><hr><h2 id="深度配置" tabindex="-1">深度配置 <a class="header-anchor" href="#深度配置" aria-label="Permalink to &quot;深度配置&quot;">​</a></h2><p>你可以通过修改 <code>~/.config/opencode/supermemory.jsonc</code> 来调整注入行为。</p><h3 id="常用配置项" tabindex="-1">常用配置项 <a class="header-anchor" href="#常用配置项" aria-label="Permalink to &quot;常用配置项&quot;">​</a></h3><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 是否注入用户画像（默认 true）</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;injectProfile&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 每次注入多少条项目记忆（默认 10）</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 调大能让 Agent 更了解项目，但会消耗更多 Token</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProjectMemories&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 每次注入多少条用户画像条目（默认 5）</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProfileItems&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 自定义触发词（支持正则）</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;keywordPatterns&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;记一下&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;永久保存&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">提示</p><p>配置修改后，需要重启 OpenCode 或重载插件才能生效。</p></div><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-注入的信息会占用很多-token-吗" tabindex="-1">Q: 注入的信息会占用很多 Token 吗？ <a class="header-anchor" href="#q-注入的信息会占用很多-token-吗" aria-label="Permalink to &quot;Q: 注入的信息会占用很多 Token 吗？&quot;">​</a></h3><p><strong>A</strong>: 会占用一部分，但通常可控。默认配置下（10条项目记忆 + 5条画像），大约占用 500-1000 Token。对于现代大模型（如 Claude 3.5 Sonnet）的 200k 上下文来说，这只是九牛一毛。</p><h3 id="q-为什么我说了-remember-它没反应" tabindex="-1">Q: 为什么我说了 &quot;remember&quot; 它没反应？ <a class="header-anchor" href="#q-为什么我说了-remember-它没反应" aria-label="Permalink to &quot;Q: 为什么我说了 &quot;remember&quot; 它没反应？&quot;">​</a></h3><p><strong>A</strong>:</p><ol><li>检查是否拼写正确（支持正则匹配）。</li><li>确认 API Key 是否配置正确（如果插件未初始化，不会触发）。</li><li>Agent 可能决定忽略（虽然插件强制提示了，但 Agent 有最终决定权）。</li></ol><h3 id="q-相关记忆-是怎么搜出来的" tabindex="-1">Q: &quot;相关记忆&quot; 是怎么搜出来的？ <a class="header-anchor" href="#q-相关记忆-是怎么搜出来的" aria-label="Permalink to &quot;Q: &quot;相关记忆&quot; 是怎么搜出来的？&quot;">​</a></h3><p><strong>A</strong>: 它是基于你 <strong>第一条消息的内容</strong> 进行语义搜索的。如果你第一句话只说了 &quot;Hi&quot;，可能搜不出什么有用的相关记忆，但 &quot;项目知识&quot; 和 &quot;用户画像&quot; 依然会被注入。</p><hr><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li><strong>自动注入</strong> 仅在会话第一条消息触发。</li><li><strong>三维模型</strong> 包含用户画像、项目知识和相关记忆。</li><li><strong>关键词触发</strong> 让你可以随时命令 Agent 保存记忆。</li><li>通过 <strong>配置文件</strong> 可以控制注入的信息量。</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../tools/">工具集详解：教 Agent 记忆</a></strong>。</p><p>你会学到：</p><ul><li>如何手动使用 <code>add</code>、<code>search</code> 等工具。</li><li>如何查看和删除错误的记忆。</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>注入触发逻辑</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L125-L176" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>125-176</td></tr><tr><td>关键词检测</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L34-L37" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>34-37</td></tr><tr><td>Prompt 格式化</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/context.ts#L14-L64" target="_blank" rel="noreferrer"><code>src/services/context.ts</code></a></td><td>14-64</td></tr><tr><td>默认配置</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L44-L54" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>44-54</td></tr></tbody></table><p><strong>关键函数</strong>：</p><ul><li><code>formatContextForPrompt()</code>: 组装 <code>[SUPERMEMORY]</code> 文本块。</li><li><code>detectMemoryKeyword()</code>: 正则匹配用户消息中的触发词。</li></ul></details><h2 id="下一课预告-1" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告-1" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../tools/">工具集详解：教 Agent 记忆</a></strong>。</p><p>你会学到：</p><ul><li>掌握 <code>add</code>, <code>search</code>, <code>profile</code> 等 5 种核心工具模式</li><li>如何手动干预和修正 Agent 的记忆</li><li>使用自然语言触发记忆保存</li></ul></blockquote>`,57)])])}const g=t(o,[["render",i]]);export{u as __pageData,g as default};
